import{_ as t}from"./chunks/feature-mapping-step1.DSj0Hfx_.js";import{_ as o,o as a,c as i,ag as r}from"./chunks/framework.1N8rnUr9.js";const n="/tubebay/assets/feature-mapping-step2.DyaCdUR8.png",l="/tubebay/assets/feature-mapping-step3.DsPqJKRD.png",s="/tubebay/assets/feature-mapping-step4.vkrOWqtb.png",f=JSON.parse('{"title":"Product Mapping","description":"","frontmatter":{},"headers":[],"relativePath":"features/product-mapping.md","filePath":"features/product-mapping.md","lastUpdated":1775898919000}'),p={name:"features/product-mapping.md"};function c(d,e,u,m,h,g){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="product-mapping" tabindex="-1">Product Mapping <a class="header-anchor" href="#product-mapping" aria-label="Permalink to &quot;Product Mapping&quot;">​</a></h1><p>Product Mapping is the core feature of TubeBay. it allows you to link specific YouTube videos to your WooCommerce products, making your store more interactive and helping customers see your products in action.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>Each video in your synced library can be &quot;Attached&quot; to one or more WooCommerce products. Once attached, the video will automatically appear on the single product page of your store.</p><h2 id="mapping-a-video" tabindex="-1">Mapping a Video <a class="header-anchor" href="#mapping-a-video" aria-label="Permalink to &quot;Mapping a Video&quot;">​</a></h2><p>Unlike traditional mapping where you link from a library, TubeBay allows you to link videos directly while you are editing your products.</p><ol><li>Go to <strong>Products &gt; All Products</strong> and edit the product you want to add a video to. Look for the <strong>TubeBay Video</strong> meta box in the sidebar and click <strong>Select Video from Library</strong>.</li></ol><p><img src="'+t+'" alt="Step 1: Meta Box Location"></p><ol start="2"><li>A modal will open displaying your entire synced YouTube library. Simply click on any video thumbnail to select it for this product.</li></ol><p><img src="'+n+'" alt="Step 2: Video Selection Modal"></p><ol start="3"><li>Once selected, you will see a preview of the video inside the meta box. You can change it at any time by clicking the edit icon or remove it entirely.</li></ol><p><img src="'+l+'" alt="Step 3: Selected Video Preview"></p><ol start="4"><li>Finally, click the <strong>Update</strong> or <strong>Publish</strong> button in the WooCommerce &quot;Publish&quot; box to save your mapping.</li></ol><p><img src="'+s+'" alt="Step 4: Save Mapping"></p><hr><h2 id="mapping-multiple-products" tabindex="-1">Mapping Multiple Products <a class="header-anchor" href="#mapping-multiple-products" aria-label="Permalink to &quot;Mapping Multiple Products&quot;">​</a></h2><p>Each WooCommerce product can be mapped to one YouTube video. If you want to change the video, simply click the <strong>Select Video from Library</strong> button again in the meta box and choose a new one.</p><hr><h2 id="technical-details" tabindex="-1">Technical Details <a class="header-anchor" href="#technical-details" aria-label="Permalink to &quot;Technical Details&quot;">​</a></h2><ul><li><strong>Storage:</strong> Mappings are stored in a custom WordPress database table (<code>wp_tubebay_mappings</code>).</li><li><strong>Performance:</strong> TubeBay uses optimized queries to fetch mapped videos, ensuring your product pages remain fast.</li><li><strong>Auto-Sync:</strong> If you delete a product in WooCommerce, the mapping will automatically be cleaned up during the next sync.</li><li><strong>Persistent Links:</strong> Once a video is mapped, the link remains until you manually unmap it or delete the product.</li></ul><h2 id="product-search" tabindex="-1">Product Search <a class="header-anchor" href="#product-search" aria-label="Permalink to &quot;Product Search&quot;">​</a></h2><p>The mapping search bar utilizes the WooCommerce product search API, allowing you to find products by:</p><ul><li>Title</li><li>SKU</li><li>ID</li></ul>',23)])])}const _=o(p,[["render",c]]);export{f as __pageData,_ as default};
